"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[53],{1109:e=>{e.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Gramble tutorial","href":"/gramble/docs/intro","docId":"intro"},{"type":"category","label":"Tutorial for Non-programmers","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"What is Gramble?","href":"/gramble/docs/tutorial/gs1","docId":"tutorial/gs1"},{"type":"link","label":"What\'s a Gramble program?","href":"/gramble/docs/tutorial/gs2","docId":"tutorial/gs2"},{"type":"link","label":"Your first program","href":"/gramble/docs/tutorial/gs3","docId":"tutorial/gs3"},{"type":"link","label":"Your second program","href":"/gramble/docs/tutorial/gs4","docId":"tutorial/gs4"},{"type":"link","label":"Your first program","href":"/gramble/docs/tutorial/gs5","docId":"tutorial/gs5"}],"href":"/gramble/docs/category/tutorial-for-non-programmers"},{"type":"category","label":"Tutorial - Basics","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Create a Page","href":"/gramble/docs/tutorial-basics/create-a-page","docId":"tutorial-basics/create-a-page"},{"type":"link","label":"Create a Document","href":"/gramble/docs/tutorial-basics/create-a-document","docId":"tutorial-basics/create-a-document"},{"type":"link","label":"Create a Blog Post","href":"/gramble/docs/tutorial-basics/create-a-blog-post","docId":"tutorial-basics/create-a-blog-post"},{"type":"link","label":"Markdown Features","href":"/gramble/docs/tutorial-basics/markdown-features","docId":"tutorial-basics/markdown-features"},{"type":"link","label":"Deploy your site","href":"/gramble/docs/tutorial-basics/deploy-your-site","docId":"tutorial-basics/deploy-your-site"},{"type":"link","label":"Congratulations!","href":"/gramble/docs/tutorial-basics/congratulations","docId":"tutorial-basics/congratulations"}],"href":"/gramble/docs/category/tutorial---basics"},{"type":"category","label":"Tutorial - Extras","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Manage Docs Versions","href":"/gramble/docs/tutorial-extras/manage-docs-versions","docId":"tutorial-extras/manage-docs-versions"},{"type":"link","label":"Translate your site","href":"/gramble/docs/tutorial-extras/translate-your-site","docId":"tutorial-extras/translate-your-site"}],"href":"/gramble/docs/category/tutorial---extras"},{"type":"link","label":"Multiple tiers","href":"/gramble/docs/multiTier","docId":"multiTier"}]},"docs":{"intro":{"id":"intro","title":"Gramble tutorial","description":"Gramble is a declarative, domain-specific programming language (DSL) for linguistic parsing and generation.  If you\'ve heard of the XFST, LEXC, or TWOLC languages, it fits roughly into the same niche, but it\'s got a rather different syntax/semantics/philosophy.","sidebar":"tutorialSidebar"},"multiTier":{"id":"multiTier","title":"Why multiple tiers?","description":"A lot of the original motivation for Gramble (or, to be precise, the systems that preceded Gramble) is that we needed systems that could express relationships between more than two tiers.","sidebar":"tutorialSidebar"},"tutorial-basics/congratulations":{"id":"tutorial-basics/congratulations","title":"Congratulations!","description":"You have just learned the basics of Docusaurus and made some changes to the initial template.","sidebar":"tutorialSidebar"},"tutorial-basics/create-a-blog-post":{"id":"tutorial-basics/create-a-blog-post","title":"Create a Blog Post","description":"Docusaurus creates a page for each blog post, but also a blog index page, a tag system, an RSS feed...","sidebar":"tutorialSidebar"},"tutorial-basics/create-a-document":{"id":"tutorial-basics/create-a-document","title":"Create a Document","description":"Documents are groups of pages connected through:","sidebar":"tutorialSidebar"},"tutorial-basics/create-a-page":{"id":"tutorial-basics/create-a-page","title":"Create a Page","description":"Add Markdown or React files to src/pages to create a standalone page:","sidebar":"tutorialSidebar"},"tutorial-basics/deploy-your-site":{"id":"tutorial-basics/deploy-your-site","title":"Deploy your site","description":"Docusaurus is a static-site-generator (also called Jamstack).","sidebar":"tutorialSidebar"},"tutorial-basics/markdown-features":{"id":"tutorial-basics/markdown-features","title":"Markdown Features","description":"Docusaurus supports Markdown and a few additional features.","sidebar":"tutorialSidebar"},"tutorial-extras/manage-docs-versions":{"id":"tutorial-extras/manage-docs-versions","title":"Manage Docs Versions","description":"Docusaurus can manage multiple versions of your docs.","sidebar":"tutorialSidebar"},"tutorial-extras/translate-your-site":{"id":"tutorial-extras/translate-your-site","title":"Translate your site","description":"Let\'s translate docs/intro.md to French.","sidebar":"tutorialSidebar"},"tutorial/gs1":{"id":"tutorial/gs1","title":"What is Gramble?","description":"Gramble is a programming language for linguistic programming: building tools that create or respond to human language words and sentences.  It\'s meant to be easier to read and write, so that people can make linguistic programs in their languages without necessarily having to have a degree in computer science.","sidebar":"tutorialSidebar"},"tutorial/gs2":{"id":"tutorial/gs2","title":"What is a Gramble program?","description":"A Gramble program is a way of specifying a linguistic database in an efficient manner, without having to list out every possible entry.  This is useful for very complex languages like Swahili or Kanyen\'keha (in which there are millions of possible verb forms), or for syntactic phenomena like sentences (where we can\'t possibly list every possible sentence), or for procedures like Romanization where you want to produce a Roman-alphabet version of any user input, even if it\'s not a word you\'ve ever seen before.","sidebar":"tutorialSidebar"},"tutorial/gs3":{"id":"tutorial/gs3","title":"Your first Gramble program","description":"Okay, let\'s make a program that does something!  We\'ll start with a verb conjugator.  This isn\'t the only kind of program you can make with Gramble, but it\'s the prototypical one.","sidebar":"tutorialSidebar"},"tutorial/gs4":{"id":"tutorial/gs4","title":"Your first Gramble program","description":"We\'ll use Swahili verbs for illustration.  Swahili is the first or second language for more than 100 million people in East Africa, and serves as a regional lingua franca.  Swahili verbs are fairly complex overall, but there are parts of the verb system that are relatively straightforward, and we\'ll start with those.","sidebar":"tutorialSidebar"},"tutorial/gs5":{"id":"tutorial/gs5","title":"Your first Gramble program","description":"We\'ll use Swahili verbs for illustration.  Swahili is the first or second language for more than 100 million people in East Africa, and serves as a regional lingua franca.  Swahili verbs are fairly complex overall, but there are parts of the verb system that are relatively straightforward, and we\'ll start with those.","sidebar":"tutorialSidebar"}}}')}}]);